      "keystrokes": "python3 - << 'PY'
import os, csv, sys, glob
os.makedirs('work', exist_ok=True)
if not os.path.exists('work/train.txt'):
    # Try to find a CSV/TSV in data/
    candidates = glob.glob('data/*.csv') + glob.glob('data/*.tsv') + glob.glob('data/*.txt')
    found = None
    for f in candidates:
        # Skip potential already-fasttext formatted train/valid
        if os.path.basename(f) in ('train.txt','valid.txt','test.txt'): continue
        # Inspect first line
        with open(f, 'r', encoding='utf-8', errors='ignore') as fh:
            head = fh.readline()
        if ',' in head or '\t' in head:
            found = f
            break
    if not found:
        print('No obvious CSV/TSV found to convert')
        sys.exit(0)
    # Heuristics: find text and label columns
    sep = '\t' if found.endswith('.tsv') else ','
    with open(found, 'r', encoding='utf-8', errors='ignore') as fh:
        sniffer = csv.Sniffer()
        sample = fh.read(4096)
        fh.seek(0)
        has_header = False
        try:
            has_header = sniffer.has_header(sample)
        except Exception:
            pass
        reader = csv.reader(fh, delimiter=sep)
        header = next(reader) if has_header else None
        rows = []
        for i, row in enumerate(reader):
            if not row: continue
            rows.append(row)
            if i >= 9999: break
    # Guess columns: prefer columns named like 'text','review','content' for text; 'label','stars','rating' for label
    def guess_idx(names, cand):
        low = [n.lower() for n in names]
        for k in cand:
            if k in low:
                return low.index(k)
        return None
    if header:
        txt_idx = guess_idx(header, ['text','review','content','sentence'])
        lbl_idx = guess_idx(header, ['label','stars','rating','sentiment','class','score'])
    else:
        # Without header, assume first col label, second col text
        txt_idx, lbl_idx = 1, 0
    if txt_idx is None or lbl_idx is None:
        # fallback: assume two columns, label then text
        txt_idx = 1 if len(rows[0])>1 else 0
        lbl_idx = 0 if len(rows[0])>1 else None
    print('Converting', found, 'using label idx', lbl_idx, 'text idx', txt_idx)
    # Write fastText format and split 90/10 for valid
    import random
    random.seed(42)
    out_train = open('work/train.txt','w',encoding='utf-8')
    out_valid = open('work/valid.txt','w',encoding='utf-8')
    with open(found, 'r', encoding='utf-8', errors='ignore') as fh:
        reader = csv.reader(fh, delimiter=sep)
        if header:
            next(reader, None)
        for row in reader:
            if not row: continue
            if lbl_idx is None or txt_idx is None or txt_idx>=len(row) or (lbl_idx is not None and lbl_idx>=len(row)):
                continue
            text = row[txt_idx].strip().replace('\n',' ') if row[txt_idx] else ''
            label = row[lbl_idx].strip() if lbl_idx is not None else ''
            if text == '' or label == '':
                continue
            # Normalize label to __label__X, mapping stars to ints etc.
            label = str(label).strip()
            # If label appears numeric like 1-5, keep as is
            lab = f"__label__{label}"
            line = f"{lab} {text}\n"
            if random.random() < 0.1:
                out_valid.write(line)
            else:
                out_train.write(line)
    out_train.close(); out_valid.close()
    print('Wrote work/train.txt and work/valid.txt')
PY
